import { readFileSync } from 'fs';
import { resolve, dirname } from 'path';
import { fileURLToPath } from 'url';

import template from './svgr-template.js';

const __dirname = dirname(fileURLToPath(import.meta.url));

const config = {
  typescript: true,
  icon: true,
  exportType: 'named',
  filenameCase: 'kebab',
  template,
  prettier: false,

  // No SVGO — preserve original SVG as-is (post-processing removes Figma artifacts)
  svgo: false,

  svgProps: {
    className: '{cn(className)}',
  },

  // Append to existing index.ts (generated by first svgr run) instead of overwriting
  indexTemplate: (filePaths) => {
    const indexPath = resolve(__dirname, 'src/components/icons/index.ts');
    let existing = '';
    try {
      existing = readFileSync(indexPath, 'utf-8');
    } catch {
      // index.ts doesn't exist yet
    }

    const newExports = filePaths.map((filePath) => {
      const filename = filePath.path.split(/[\\/]/).pop().replace('.tsx', '');
      const componentName = filename
        .split('-')
        .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
        .join('');
      return `export { ${componentName} } from './${filename}';`;
    });

    // Filter out existing lines that will be replaced by new exports
    const newFilenames = new Set(
      filePaths.map((fp) => fp.path.split(/[\\/]/).pop().replace('.tsx', ''))
    );
    const existingLines = existing.split('\n').filter((line) => {
      if (!line.trim()) return false;
      const match = line.match(/from\s+['"]\.\/([^'"]+)['"]/);
      return !match || !newFilenames.has(match[1]);
    });

    return [...existingLines, ...newExports].join('\n') + '\n';
  },
};

export default config;
